// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.io.File;
import java.util.concurrent.atomic.AtomicReference;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.ArbitraryLengthPath;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.helpers.AbstractSimpleQueryModelVisitor;
import org.eclipse.rdf4j.query.explanation.Explanation;
import org.eclipse.rdf4j.query.explanation.TelemetryMetricNames;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class LmdbPropertyPathEstimateTest {

	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void annotatesArbitraryLengthPathWithPropertyPathEstimate(@TempDir File dataDir) {
		LmdbStore store = new LmdbStore(dataDir);
		SailRepository repository = new SailRepository(store);
		repository.init();
		try {
			IRI a = VF.createIRI("urn:a");
			IRI b = VF.createIRI("urn:b");
			IRI c = VF.createIRI("urn:c");
			IRI p = VF.createIRI("urn:p");
			try (SailRepositoryConnection connection = repository.getConnection()) {
				connection.add(a, p, b);
				connection.add(b, p, c);
				store.getBackingStore().getSketchBasedJoinEstimator().rebuild();

				Explanation explanation = connection.prepareTupleQuery("SELECT ?o WHERE { <urn:a> <urn:p>+ ?o }")
						.explain(Explanation.Level.Optimized);
				ArbitraryLengthPath path = findArbitraryLengthPath((TupleExpr) explanation.tupleExpr());

				assertNotNull(path, explanation::toString);
				String proof = path.getStringMetricPlanned("optimizer.rewriteProof");
				assertTrue(proof != null && proof.contains("PROPERTY_PATH_COST_ANNOTATION"), explanation::toString);
				assertTrue("lmdb-property-path".equals(
						path.getStringMetricPlanned(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE)),
						explanation::toString);
			}
		} finally {
			try {
				repository.shutDown();
			} finally {
				LmdbTestUtil.deleteDir(dataDir);
			}
		}
	}

	private static ArbitraryLengthPath findArbitraryLengthPath(TupleExpr tupleExpr) {
		AtomicReference<ArbitraryLengthPath> result = new AtomicReference<>();
		tupleExpr.visit(new AbstractSimpleQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(ArbitraryLengthPath node) {
				result.compareAndSet(null, node);
			}
		});
		return result.get();
	}
}
